using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Research Agent – searches the web, takes notes, then summarises findings.
// ---------------------------------------------------------------------------

var topic = args.Length > 0 ? string.Join(' ', args) : "the latest advances in quantum computing";

Console.WriteLine($"🔍  Research Agent starting – topic: \"{topic}\"\n");

// --- Chat client with tool support ----------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient innerClient = new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient();

var notebook = new Notebook();

IChatClient agent = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearchTool.SearchAsync),
        AIFunctionFactory.Create(notebook.AddNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ]
};

// --- Agent loop ------------------------------------------------------------

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research assistant. Your goal is to research the given topic
        thoroughly, then produce a well-structured summary.

        Workflow:
        1. Search the web 2-3 times with varied queries to gather information.
        2. After each search, save the most important facts using the note-taking tool.
        3. Once you have enough information, retrieve all your notes and write a
           final summary for the user. The summary should be informative and cite
           the sources (URLs) where possible.
        """),
    new(ChatRole.User, $"Please research the following topic and summarise your findings:\n\n{topic}")
];

var response = await agent.GetResponseAsync(messages, chatOptions);
Console.WriteLine("\n===== RESEARCH SUMMARY =====\n");
Console.WriteLine(response);

