// Tools
// ---------------------------------------------------------------------------

/// <summary>Web search tool – fetches search results via DuckDuckGo Lite.</summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" }
        }
    };

    [Description("Searches the web for the given query and returns a list of result titles, snippets, and URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐  Searching: \"{query}\"");
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://lite.duckduckgo.com/lite?q={encoded}";
            var html = await Http.GetStringAsync(url);
            var results = ParseDuckDuckGoLite(html);

            if (results.Count == 0)
                return "No results found.";

            return JsonSerializer.Serialize(results.Take(6),
                new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseDuckDuckGoLite(string html)
    {
        // DDG Lite returns a simple HTML table with results.
        var results = new List<SearchResult>();
        var span = html.AsSpan();
        const string linkMarker = "class=\"result-link\"";

        int pos = 0;
        while (pos < span.Length && results.Count < 8)
        {
            int linkIdx = html.IndexOf(linkMarker, pos, StringComparison.Ordinal);
            if (linkIdx < 0) break;

            // Extract href
            int hrefStart = html.LastIndexOf("href=\"", linkIdx, Math.Min(linkIdx, 200), StringComparison.Ordinal);
            string href = "";
            if (hrefStart >= 0)
            {
                hrefStart += 6;
                int hrefEnd = html.IndexOf('"', hrefStart);
                if (hrefEnd > hrefStart)
                    href = WebUtility.HtmlDecode(html[hrefStart..hrefEnd]);
            }

            // Extract link text (title)
            int closeTag = html.IndexOf('>', linkIdx);
            int endA = html.IndexOf("</a>", closeTag, StringComparison.Ordinal);
            string title = "";
            if (closeTag >= 0 && endA > closeTag)
                title = StripTags(WebUtility.HtmlDecode(html[(closeTag + 1)..endA])).Trim();

            // Extract snippet – next <td class="result-snippet">
            string snippet = "";
            int snippetIdx = html.IndexOf("result-snippet", endA > 0 ? endA : linkIdx, StringComparison.Ordinal);
            if (snippetIdx >= 0)
            {
                int sClose = html.IndexOf('>', snippetIdx);
                int sEnd = html.IndexOf("</td>", sClose, StringComparison.Ordinal);
                if (sClose >= 0 && sEnd > sClose)
                    snippet = StripTags(WebUtility.HtmlDecode(html[(sClose + 1)..sEnd])).Trim();
            }

            if (!string.IsNullOrEmpty(title))
                results.Add(new SearchResult(title, snippet, href));

            pos = endA > 0 ? endA + 4 : linkIdx + linkMarker.Length;
        }

        return results;
    }

    private static string StripTags(string html)
    {
        var clean = new System.Text.StringBuilder(html.Length);
        bool inside = false;
        foreach (var ch in html)
        {
            if (ch == '<') { inside = true; continue; }
            if (ch == '>') { inside = false; continue; }
            if (!inside) clean.Append(ch);
        }
        return clean.ToString();
    }

    record SearchResult(string Title, string Snippet, string Url);
}

/// <summary>Simple notebook that the agent uses to collect facts.</summary>
class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note. Use this to record important facts discovered during research.")]
    public string AddNote([Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝  Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all notes taken so far, so you can compile your final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0) return "No notes yet.";
        Console.WriteLine($"  📖  Retrieving {_notes.Count} note(s)");
        return string.Join("\n---\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

